class Solution(object):
    def maxIncreasingSubarrays(self, nums):
        n = len(nums)
        run_end = [1] * n
        for i in range(1, n):
            if nums[i] > nums[i - 1]:
                run_end[i] = run_end[i - 1] + 1
        run_start = [1] * n
        for i in range(n - 2, -1, -1):
            if nums[i] < nums[i + 1]:
                run_start[i] = run_start[i + 1] + 1
        best = 0
        for i in range(n - 1):
            best = max(best, min(run_end[i], run_start[i + 1]))
        return best
